#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int D[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &D[i]);
        }
        qsort(D, n, sizeof(int), compare);
        long long sum = 0;
        for (int i = 0; i < n / 2; i++) {
            sum += abs(D[i] + D[n - i - 1]) * (n - i - i - 1);
        }
        printf("%lld\n", sum);
    }
    return 0;
}

