import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] D = new int[n];
            for (int i = 0; i < n; i++) {
                D[i] = sc.nextInt();
            }
            Arrays.sort(D);
            long sum = 0;
            for (int i = 0; i < n / 2; i++) {
                sum += Math.abs(D[i] + D[n - i - 1]) * (n - i - i - 1);
            }
            System.out.println(sum);
        }
    }
}

