const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let n = nextInt();
    let D = nextIntArray();
    D.sort((a, b) => a - b);
    let sum = 0;
    for (let i = 0; i < n / 2; i++) {
        sum += Math.abs(D[i] + D[n - i - 1]) * (n - i - i - 1);
    }
    console.log(sum);
}
